mapper.select:
SELECT s.seller_id,s.user_id,s.company_name,u.photo_name,
/* 작가 전체 상품 리뷰 평균 */ (SELECT COALESCE(ROUND(AVG(r.rating), 1), 0) FROM products p JOIN reviews r ON p.product_id = r.product_id WHERE p.seller_id = s.seller_id AND p.status = 'APPROVED') AS review_avg,
/* 작가 전체 상품 리뷰 수 */ (SELECT COUNT(*) FROM products p JOIN reviews r ON p.product_id = r.product_id WHERE p.seller_id = s.seller_id AND p.status = 'APPROVED') AS review_count,
/* 작가 전체 상품 찜 수 */ (SELECT COUNT(*) FROM products p JOIN favorites f ON p.product_id = f.product_id WHERE p.seller_id = s.seller_id AND p.status = 'APPROVED') AS product_favorite_count
FROM sellers s JOIN users u ON s.user_id = u.user_id WHERE s.seller_id = #{seller_id}

SELECT COUNT(DISTINCT o.order_id) FROM orders o
JOIN order_items oi ON oi.order_id = o.order_id
JOIN products p ON p.product_id = oi.product_id
WHERE p.seller_id = #{seller_id}
AND o.status = #{status}

SELECT DISTINCT o.order_id, o.user_id, o.total_amount, o.address_id, o.status, o.created_at, o.updated_at,
a.recipient_name AS receiver_name, a.phone AS receiver_phone,
CONCAT( '[', IFNULL(a.zipcode, ''), '] ', IFNULL(a.address, ''), ' ', IFNULL(a.detail_address, '') ) AS delivery_address
FROM orders o JOIN order_items oi ON oi.order_id = o.order_id JOIN products p ON p.product_id = oi.product_id LEFT JOIN addresses a ON a.address_id = o.address_id
WHERE p.seller_id = #{seller_id}
AND o.status = #{status}
ORDER BY o.order_id DESC LIMIT #{size} OFFSET #{offset}
